// 显式初始化三个 Perspective WASM；+esm 不会自动定位这些二进制
const el = document.getElementById('view'); el.style.height = '400px'; el.textContent = 'Loading data grid…';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/@finos/perspective-viewer@3.8.0/dist/css/themes.css'; document.head.appendChild(css);
const [perspectiveModule, viewerModule] = await Promise.all([
  import('https://cdn.jsdelivr.net/npm/@finos/perspective@3.8.0/+esm'),
  import('https://cdn.jsdelivr.net/npm/@finos/perspective-viewer@3.8.0/+esm')
]);
await Promise.all([
  perspectiveModule.init_client(fetch('https://cdn.jsdelivr.net/npm/@finos/perspective@3.8.0/dist/wasm/perspective-js.wasm')),
  perspectiveModule.init_server(fetch('https://cdn.jsdelivr.net/npm/@finos/perspective@3.8.0/dist/wasm/perspective-server.wasm')),
  viewerModule.init_client(fetch('https://cdn.jsdelivr.net/npm/@finos/perspective-viewer@3.8.0/dist/wasm/perspective-viewer.wasm'))
]);
await import('https://cdn.jsdelivr.net/npm/@finos/perspective-viewer-datagrid@3.8.0/+esm');
el.textContent = '';
const viewer = document.createElement('perspective-viewer'); viewer.style.height = '400px'; el.appendChild(viewer);
const worker = await perspectiveModule.worker(); const table = await worker.table(data.table); await viewer.load(table); if (data.config) await viewer.restore(data.config);

